mapper.select:
select cp.id, cp.create_time, cp.update_time, cp.mch_id, cp.shop_id, cp.name, cp.description, cp.type, cp.amount, cp.discount, cp.min_amount, cp.quantity, cp.received, cp.used, cp.per_limit, cp.use_range, cp.target_id, cp.begin_time, cp.end_time, cp.sort, (select count(ucp.id) from s_member_coupon ucp where ucp.deleted = 0 and ucp.coupon_id = cp.id) as receivedCount from s_mch_coupon cp where cp.deleted = 0 and cp.is_enabled = 1
and cp.use_range = #{query.useRange}
ORDER BY CASE WHEN NOW() BETWEEN cp.begin_time AND cp.end_time THEN 3 WHEN cp.begin_time > NOW() THEN 2 ELSE 1 END DESC, cp.create_time DESC

mapper.update:
UPDATE s_mch_coupon c
SET c.received = c.received + #{count}
WHERE c.id = #{id}
AND c.quantity > c.received + #{count}
